class Solution {
    public int longestSubsequence(String s, int k) {
        int n = s.length();
        int res = 0;
        for (int i = 0; i < n; i++) {
            int num = 0;
            for (int j = i; j < n; j++) {
                num = num * 2 + (s.charAt(j) - '0');
                if (num > k) break;
                res = Math.max(res, j - i + 1);
            }
        }
        return res;
    }
}

